package adaptivefec

import (
	"math"
	"time"
)

// Controller is the pure adaptive-FEC state machine. It consumes per-path loss
// samples via Observe and emits a target parity count M for a fixed group of K
// data shards, applying EWMA smoothing, a safety-factored redundancy map,
// hysteresis, a slew-rate limit, and a lower-side dwell (see the package doc).
//
// A Controller holds no globals and does no I/O; it reads time only through its
// injected Clock. It is NOT safe for concurrent use — its owner serializes
// access, exactly as internal/telemetry.Estimator does.
type Controller struct {
	cfg   Config
	clock Clock

	// smoothed EWMA loss; seeded by the first sample.
	smoothed float64
	haveEWMA bool

	// m is the current target parity count.
	m int

	// lastChange is when m last moved; rate limiting is measured from it.
	lastChange   time.Time
	haveChanged  bool
	lowSince     time.Time // when smoothed loss last entered the <=LowerThreshold region
	haveLowSince bool
}

// NewController validates cfg and returns a Controller starting at M=0 (no
// standing redundancy until loss is observed). It fails fast on an invalid
// config or a nil clock.
func NewController(cfg Config, clock Clock) (*Controller, error) {
	if err := cfg.Validate(); err != nil {
		return nil, err
	}
	if clock == nil {
		return nil, errNilClock
	}
	return &Controller{cfg: cfg, clock: clock}, nil
}

// Observe folds one per-path loss sample, measured now (read from the injected
// Clock), into the controller and returns the resulting target parity count M.
// A loss outside [0,1] (including NaN) is a telemetry boundary artifact and is
// clamped rather than rejected, so a transient bad estimate cannot destabilize
// the loop.
func (c *Controller) Observe(loss float64) int {
	now := c.clock.Now()
	s := c.updateEWMA(clampLoss(loss))

	// Track how long smoothed loss has stayed in the lower (shed-eligible) region;
	// the dwell for a decrease is measured from lowSince.
	if s <= c.cfg.LowerThreshold {
		if !c.haveLowSince {
			c.lowSince = now
			c.haveLowSince = true
		}
	} else {
		c.haveLowSince = false
	}

	target := c.bandTarget(s, now)
	c.slewToward(target, now)
	return c.m
}

// updateEWMA folds one clamped sample into the smoothed loss and returns it. The
// first sample seeds the average directly.
func (c *Controller) updateEWMA(loss float64) float64 {
	if !c.haveEWMA {
		c.smoothed = loss
		c.haveEWMA = true
	} else {
		c.smoothed = c.cfg.Alpha*loss + (1-c.cfg.Alpha)*c.smoothed
	}
	return c.smoothed
}

// bandTarget applies the hysteresis bands to pick the parity level m should move
// toward, giving the loop three regions:
//
//   - RAISE (s >= RaiseThreshold): m may only INCREASE, toward the safety-factored
//     redundancy map. A decrease here would defeat the raise band, so it is
//     forbidden; this is why m does not oscillate while loss stays elevated.
//   - LOWER (s <= LowerThreshold): m COLLAPSES toward 0 — but only after the loss
//     has stayed quiet for the full Dwell. Being below the lower band is exactly
//     the "near-zero loss" condition, so the shed target is 0 (zero-at-zero), NOT
//     the raw map: the map's ceil() would pin any infinitesimal EWMA tail at M=1
//     and standing redundancy would never fully clear on a clean path.
//   - DEADBAND (in between): HOLD. A loss signal oscillating inside [Lower,Raise]
//     cannot move m, so it cannot flap.
//
// The raise-fast / lower-after-dwell asymmetry is the anti-thrash core.
func (c *Controller) bandTarget(s float64, now time.Time) int {
	switch {
	case s >= c.cfg.RaiseThreshold:
		return maxInt(c.m, c.redundancyMap(s))
	case s <= c.cfg.LowerThreshold:
		if c.haveLowSince && now.Sub(c.lowSince) >= c.cfg.Dwell {
			return 0
		}
		return c.m
	default:
		return c.m
	}
}

// redundancyMap converts a smoothed loss fraction into the parity count M. In the
// RESIDUAL-SLA mode (TargetResidual set) it delegates to residualTargetParity,
// which inverts the binomial residual model to the smallest M meeting the target.
// Otherwise it uses the legacy SafetyFactor map: the smallest M whose group
// tolerates safety*loss, i.e. M/(K+M) >= safety*loss:
//
//	M = ceil( K * e / (1 - e) ),  e = safety*loss
//
// e saturates to MaxParity as e -> 1, and loss <= 0 maps to exactly 0 (zero
// overhead when clean). The result is clamped to [0, MaxParity]. Both modes are
// monotone non-decreasing and zero-at-zero, so the surrounding hysteresis and
// slew machinery is identical regardless of which mode is active.
func (c *Controller) redundancyMap(loss float64) int {
	if c.cfg.TargetResidual > 0 {
		return c.residualTargetParity(loss)
	}
	e := loss * c.cfg.SafetyFactor
	if e <= 0 {
		return 0
	}
	if e >= 1 {
		return c.cfg.MaxParity
	}
	m := int(math.Ceil(float64(c.cfg.DataShards) * e / (1 - e)))
	if m < 0 {
		m = 0
	}
	if m > c.cfg.MaxParity {
		m = c.cfg.MaxParity
	}
	return m
}

// slewToward moves m toward target subject to the rate limit: m changes by at
// most MaxStep, and no change may occur until RateInterval has elapsed since the
// previous change. The first change is permitted immediately.
func (c *Controller) slewToward(target int, now time.Time) {
	if target == c.m {
		return
	}
	if c.haveChanged && now.Sub(c.lastChange) < c.cfg.RateInterval {
		return
	}
	step := target - c.m
	if step > c.cfg.MaxStep {
		step = c.cfg.MaxStep
	} else if step < -c.cfg.MaxStep {
		step = -c.cfg.MaxStep
	}
	c.m += step
	c.lastChange = now
	c.haveChanged = true
}

// Parity returns the current target parity count M without advancing state.
func (c *Controller) Parity() int { return c.m }

// SmoothedLoss returns the current EWMA loss estimate. This is a read-only
// signal a future integration MAY also feed to the weighted scheduler (T21);
// this package wires nothing.
func (c *Controller) SmoothedLoss() float64 { return c.smoothed }

// Overhead returns the current parity fraction M/(K+M): the fraction of on-wire
// shards that are parity at the present target. 0 when M is 0.
func (c *Controller) Overhead() float64 {
	if c.m == 0 {
		return 0
	}
	return float64(c.m) / float64(c.cfg.DataShards+c.m)
}

func clampLoss(loss float64) float64 {
	if math.IsNaN(loss) || loss < 0 {
		return 0
	}
	if loss > 1 {
		return 1
	}
	return loss
}

func maxInt(a, b int) int {
	if a > b {
		return a
	}
	return b
}

package adaptivefec

import (
	"fmt"
	"math"
	"time"
)

// MaxShards mirrors the Reed-Solomon field limit enforced in internal/fec
// (maxShards) and restated in internal/config (maxFECShards): a coding group
// carries at most 256 shards (data + parity) total over GF(2^8). It is mirrored
// here — with this cross-reference rather than an import — so the controller can
// fail-fast on an out-of-field parity bound without coupling to the datapath.
const MaxShards = 256

// Documented default control-law constants. They are the SINGLE SOURCE OF TRUTH
// for the tuning the simulation harness exercises; DefaultConfig assembles them.
// Every value is named and justified rather than appearing as a magic number in
// the algorithm.
const (
	// DefaultDataShards is K, the fixed number of data shards per coding group the
	// controller sizes parity for. Chosen to match a typical FEC group.
	DefaultDataShards = 10

	// DefaultMaxParity caps M at 100% overhead (M == K): beyond a 1:1 parity ratio
	// the marginal recovery per byte of overhead is poor, so the loop saturates
	// there rather than spending unbounded bandwidth under pathological loss.
	DefaultMaxParity = 10

	// DefaultAlpha is the EWMA weight of the newest loss sample. 0.3 keeps ~3-4
	// samples of memory: heavy enough to reject single-sample telemetry noise, light
	// enough to react to a genuine sustained shift within a few probe intervals.
	DefaultAlpha = 0.3

	// DefaultRaiseThreshold is the smoothed-loss level (5%) at/above which the loop
	// starts adding parity. Below it, occasional loss is cheaper to absorb via
	// retransmit/latency than to mask with standing redundancy.
	DefaultRaiseThreshold = 0.05

	// DefaultLowerThreshold is the smoothed-loss level (2%) at/below which the loop
	// is eligible to shed parity. The gap to RaiseThreshold is the hysteresis
	// deadband: loss wandering between 2% and 5% neither raises nor lowers M.
	DefaultLowerThreshold = 0.02

	// DefaultSafetyFactor is the headroom over the mean loss the parity is sized to
	// mask. 1.5 sizes each group to tolerate 1.5x the smoothed loss, covering the
	// binomial variance by which an individual group exceeds the mean. It applies
	// only when TargetResidual is unset (the legacy SafetyFactor sizing mode).
	DefaultSafetyFactor = 1.5

	// DefaultMaxStep bounds |ΔM| per RateInterval. A single spike can move M by at
	// most 2 parity shards per interval, so redundancy slews rather than jumps.
	DefaultMaxStep = 2

	// DefaultRateInterval is the minimum wall time between two M changes. Combined
	// with MaxStep it caps the redundancy slew rate at MaxStep shards per 500ms.
	DefaultRateInterval = 500 * time.Millisecond

	// DefaultDwell is how long smoothed loss must stay at/below LowerThreshold before
	// the first decrease. 3s of quiet is required to shed parity, so a brief lull in
	// a lossy period does not prematurely strip protection (raise fast, lower slow).
	DefaultDwell = 3 * time.Second
)

// Config parameterizes the adaptive FEC controller. All fields are validated at
// construction (fail-fast): a mis-tuned band or an out-of-field parity bound is
// rejected by NewController rather than producing undefined control behavior at
// runtime.
type Config struct {
	// DataShards is K, the fixed group size the controller sizes parity for. >= 1.
	DataShards int
	// MaxParity is the upper bound on the emitted M. >= 1 and DataShards+MaxParity
	// <= MaxShards (the Reed-Solomon field limit).
	MaxParity int
	// Alpha is the EWMA weight of the newest loss sample, in (0,1]. Smaller = more
	// smoothing.
	Alpha float64
	// RaiseThreshold is the smoothed-loss level at/above which M may rise. In
	// (LowerThreshold, 1).
	RaiseThreshold float64
	// LowerThreshold is the smoothed-loss level at/below which M may fall. In
	// [0, RaiseThreshold). The gap to RaiseThreshold is the hysteresis deadband.
	LowerThreshold float64
	// SafetyFactor is the headroom multiplier on the smoothed loss the parity is
	// sized to mask. >= 1 in the SafetyFactor sizing mode (TargetResidual unset);
	// MUST be 0 when TargetResidual is set (the two modes are mutually exclusive).
	SafetyFactor float64
	// TargetResidual, when set (> 0), selects the RESIDUAL-SLA sizing mode and is
	// the PRIMARY parity surface: instead of the bare SafetyFactor multiplier the
	// controller derives M by inverting the binomial residual model
	// E[max(0,D-M)]/K (D ~ Bin(K, smoothed loss), see residual.go) to the smallest
	// M whose modeled residual is <= TargetResidual, clamped to [0, MaxParity]. It
	// SUPERSEDES SafetyFactor (which must be 0 when this is set). Must be in (0,1)
	// when set; 0 selects the legacy SafetyFactor path.
	TargetResidual float64
	// MaxStep bounds |ΔM| applied per RateInterval. >= 1.
	MaxStep int
	// RateInterval is the minimum time between two M changes. > 0.
	RateInterval time.Duration
	// Dwell is the minimum time smoothed loss must stay at/below LowerThreshold
	// before the first decrease. >= 0.
	Dwell time.Duration
}

// DefaultConfig returns a Config populated from the documented default control
// constants.
func DefaultConfig() Config {
	return Config{
		DataShards:     DefaultDataShards,
		MaxParity:      DefaultMaxParity,
		Alpha:          DefaultAlpha,
		RaiseThreshold: DefaultRaiseThreshold,
		LowerThreshold: DefaultLowerThreshold,
		SafetyFactor:   DefaultSafetyFactor,
		MaxStep:        DefaultMaxStep,
		RateInterval:   DefaultRateInterval,
		Dwell:          DefaultDwell,
	}
}

// Validate enforces the control-law invariants, failing fast so a mis-tuned
// controller is rejected at construction rather than misbehaving at runtime.
func (c Config) Validate() error {
	if c.DataShards < 1 {
		return fmt.Errorf("adaptivefec: DataShards (K) must be >= 1, got %d", c.DataShards)
	}
	if c.MaxParity < 1 {
		return fmt.Errorf("adaptivefec: MaxParity must be >= 1, got %d", c.MaxParity)
	}
	if c.DataShards+c.MaxParity > MaxShards {
		return fmt.Errorf("adaptivefec: DataShards+MaxParity must be <= %d (Reed-Solomon field limit), got %d", MaxShards, c.DataShards+c.MaxParity)
	}
	if !(c.Alpha > 0 && c.Alpha <= 1) || math.IsNaN(c.Alpha) {
		return fmt.Errorf("adaptivefec: Alpha must be in (0,1], got %g", c.Alpha)
	}
	if math.IsNaN(c.LowerThreshold) || c.LowerThreshold < 0 {
		return fmt.Errorf("adaptivefec: LowerThreshold must be >= 0, got %g", c.LowerThreshold)
	}
	if math.IsNaN(c.RaiseThreshold) || c.RaiseThreshold >= 1 {
		return fmt.Errorf("adaptivefec: RaiseThreshold must be < 1, got %g", c.RaiseThreshold)
	}
	if c.LowerThreshold >= c.RaiseThreshold {
		return fmt.Errorf("adaptivefec: LowerThreshold (%g) must be < RaiseThreshold (%g) so the hysteresis deadband is non-empty", c.LowerThreshold, c.RaiseThreshold)
	}
	if math.IsNaN(c.TargetResidual) {
		return fmt.Errorf("adaptivefec: TargetResidual must be a number, got NaN")
	}
	if c.TargetResidual != 0 {
		// Residual-SLA sizing mode: TargetResidual governs and SafetyFactor is inert,
		// so the two must not both be set (mutually exclusive, fail-fast).
		if c.TargetResidual < 0 || c.TargetResidual >= 1 {
			return fmt.Errorf("adaptivefec: TargetResidual must be in (0,1) when set, got %g", c.TargetResidual)
		}
		if c.SafetyFactor != 0 {
			return fmt.Errorf("adaptivefec: SafetyFactor and TargetResidual are mutually exclusive (TargetResidual is the primary residual-SLA surface); leave SafetyFactor 0 when TargetResidual is set, got SafetyFactor=%g", c.SafetyFactor)
		}
	} else if math.IsNaN(c.SafetyFactor) || math.IsInf(c.SafetyFactor, 0) || c.SafetyFactor < 1 {
		return fmt.Errorf("adaptivefec: SafetyFactor must be a finite value >= 1 (or set TargetResidual instead), got %g", c.SafetyFactor)
	}
	if c.MaxStep < 1 {
		return fmt.Errorf("adaptivefec: MaxStep must be >= 1, got %d", c.MaxStep)
	}
	if c.RateInterval <= 0 {
		return fmt.Errorf("adaptivefec: RateInterval must be > 0, got %s", c.RateInterval)
	}
	if c.Dwell < 0 {
		return fmt.Errorf("adaptivefec: Dwell must be >= 0, got %s", c.Dwell)
	}
	return nil
}

package bind

import (
	"encoding/binary"
	"fmt"
	"sync"
	"sync/atomic"
	"time"

	"github.com/7mind/wanbond/internal/adaptivefec"
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/telemetry"
)

// FEC datapath integration (T24).
//
// The fixed-ratio Reed-Solomon engine (internal/fec) is wired into the multipath
// datapath as a SEND-side encoder and a RECEIVE-side decoder that composes with the
// T18 resequencer, T21 weighted scheduling, and T30 dynamic paths without regressing
// any of them. FEC is OFF unless a config carries an [fec] block (NewMultipath's
// fecCfg is nil otherwise), in which case the datapath is byte-for-byte the pre-T24
// behaviour.
//
// Wire mapping. The FEC data-shard bytes are OuterSeq || inner: the encoder codes
// parity over that, but the 8-byte outer-seq prefix is NOT transmitted — the DATA
// frame carries the outer-seq in its header and the inner datagram in its payload,
// and both sender and receiver reconstitute the shard bytes as
// header-seq || frame-payload. This keeps a recovered shard SELF-DESCRIBING (its
// reconstructed bytes carry its own outer-seq, so a frame reconstructed from parity
// resequences at its ORIGINAL outer-seq even when EVERY data frame of the group was
// lost) while adding only one wire byte per DATA frame (the shard index in the DATA
// header) and the group cardinality M per PARITY frame. See internal/frame.
//
// Concurrency. The encoder rides the Send path, already serialized under m.mu, plus
// a single deadline-tick goroutine that TryLocks m.mu (never blocking, so it can
// never deadlock Close's readersWG.Wait held under m.mu — the tickLivenessFromReceive
// discipline). The decoder is fed from the per-path readLoop goroutines (many
// concurrent), so it is guarded by its own mutex, disjoint from m.mu and from the
// resequencer's — matching the resequencer's lock discipline (never held across a
// syscall). Recovered frames are handed to the resequencer exactly like a
// natively-received frame, so FEC recovery slots in strictly BEFORE resequencing.

// fecSeqPrefixLen is the width of the big-endian outer-seq prefix that heads each
// FEC data-shard's coded bytes. It is reconstructed from the DATA frame header on
// both ends and never travels the wire (see the wire mapping above).
const fecSeqPrefixLen = 8

// maxFECDeadline is the authoritative upper bound on the FEC group-close deadline,
// coupling it to the receive resequencer's per-gap timeout (T24, defect #4). A group
// flushed by the deadline emits its parity `deadline` after the group opened; the
// reconstructed frames must reach the resequencer BEFORE it skips the gap
// (resequencerTimeout after the gap forms), or recovery is structurally too late — the
// gap is skipped first and the recovered frame dropped as past the release point. Held
// at half the resequencer timeout, the deadline leaves the other half for propagation
// and reconstruction. config validation enforces a matching load-time bound; this is
// the authoritative guard for any fec.Config built directly.
const maxFECDeadline = resequencerTimeout / 2

// fecRetainGroups bounds the decoder's retained-group window (SetRetainWindow): a
// group more than this many group-ids behind the newest offered group is evicted,
// which is also when an incomplete group is finally accounted unrecoverable. It is
// sized well above the reorder/loss span a single group can straddle so a group is
// never evicted while its own shards are still legitimately in flight, yet small
// enough that an unrecoverable group is accounted promptly rather than after a
// 4096-group default. A group spans a handful of outer-seqs, so this comfortably
// exceeds the resequencerWindow's reordering budget in group units.
const fecRetainGroups = 512

// fecResidualLossWindow is the trailing outer-seq width of the receive-side residual-
// loss estimator (T29): the post-FEC-recovery loss the P4 acceptance bounds. It is
// deliberately WIDER than the telemetry default (512) for two reasons: (1) resolution —
// the P4 bound is 0.5%, so the window must resolve finer than 1/512≈0.2%; 8192 gives
// ~0.012% granularity, well under the bound; (2) stability — averaging the residual over
// ~thousands of groups smooths the per-group binomial variance into a steady-state figure.
// It stays far below the resequencer window's reordering budget, and is wide enough that a
// recovered frame arriving a group or two after its gap still retroactively fills it, so
// genuinely-unrecovered seqs (whole-group and beyond-budget losses) are the only residual.
const fecResidualLossWindow = 8192

// adaptiveControlInterval throttles how often the FEC tick loop folds a fresh loss
// sample into the adaptive controller (T29). It matches the probe cadence — the rate at
// which per-path loss estimates actually refresh — so the controller's EWMA sees ~one
// sample per probe interval as its tuning (internal/adaptivefec) assumes, regardless of
// the (possibly much smaller) FEC group-close deadline the tick loop runs at.
const adaptiveControlInterval = telemetry.DefaultProbeInterval

// fecSender is the send-side FEC state: the group-forming encoder (accessed only
// under the Bind's m.mu, on the Send path and the deadline-tick goroutine) plus the
// parity-overhead counters the /metrics exposition reports. The counters are
// atomics read lock-free at snapshot time, mirroring the T23 per-path byte counters.
type fecSender struct {
	enc *fec.Encoder

	// ctrl is the adaptive-FEC controller (T29), nil in fixed-ratio mode. It is driven
	// (Observe) and read (Parity) ONLY from under the Bind's m.mu — the FEC tick loop's
	// throttled drive and, transitively, the Send path — so it needs no lock of its own,
	// matching the encoder's single-writer discipline. lastControlTick/haveControlTick
	// throttle the drive to adaptiveControlInterval and are likewise m.mu-guarded.
	ctrl            *adaptivefec.Controller
	lastControlTick time.Time
	haveControlTick bool

	dataFrames   atomic.Uint64
	dataBytes    atomic.Uint64
	parityFrames atomic.Uint64
	parityBytes  atomic.Uint64
}

// fecReceiver is the receive-side FEC state: the recovery decoder guarded by its own
// mutex (the per-path readLoop goroutines feed it concurrently). deliveredRecovered is
// the HONEST recovery count for /metrics — data frames a reconstruction actually
// delivered to the resequencer AHEAD of its release point (not merely reconstructed:
// a frame rebuilt after the resequencer already skipped its gap is dropped as late and
// must not be counted, else /metrics overstates recovery). It is an atomic so the
// snapshot reads it lock-free.
type fecReceiver struct {
	mu  sync.Mutex
	dec *fec.Decoder

	deliveredRecovered atomic.Uint64

	// connLoss is the POST-FEC-RECOVERY residual-loss estimator (T29, the P4 signal):
	// every natively-received DATA outer-seq AND every FEC-reconstructed outer-seq is
	// Observed into it, so its Loss() fraction is exactly the connection-scoped loss that
	// survived FEC — outer-seqs neither received nor recovered. It is internally
	// synchronized (its own mutex), fed concurrently by the per-path readLoop goroutines
	// exactly like the resequencer, and read lock-free-enough at scrape time.
	connLoss *telemetry.ConnLoss
}

// offer feeds one surviving shard into the decoder and returns any data payloads it
// reconstructed (never-received frames). It holds the decoder mutex only for the
// in-memory reconstruct — never across a syscall — so it never blocks the send path.
func (r *fecReceiver) offer(s fec.Shard) ([]fec.Recovered, error) {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.dec.Offer(s)
}

// stats snapshots the decoder's cumulative recovery counters under its mutex.
func (r *fecReceiver) stats() fec.DecoderStats {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.dec.Stats()
}

// FECStats is a consistent snapshot of the Bind's FEC counters (T24), the shape the
// metrics.Source adapter maps onto the connection-scoped /metrics FEC series.
// DataFrames is the send-side DATA-frame count (the fixed-ratio overhead's
// denominator); ParityFrames/ParityBytes are the send-side overhead (parity emitted);
// Recovered and Unrecoverable are the receive-side outcome (data shards reconstructed
// from parity, and data shards lost beyond repair capacity). FEC being
// connection-scoped, these carry no path label. The frame overhead the operator cares
// about is ParityFrames/DataFrames, which tends to ParityShards/DataShards (M/K) once
// groups fill; both are counted only for frames that actually reached the socket, so
// the ratio reflects wire cost actually spent.
type FECStats struct {
	DataFrames    uint64
	DataBytes     uint64
	ParityFrames  uint64
	ParityBytes   uint64
	Recovered     uint64
	Unrecoverable uint64
	// ResidualLoss is the current post-FEC-recovery connection loss fraction in [0,1]
	// (T29): the share of outer-seqs neither natively received nor reconstructed from
	// parity. It is the P4 acceptance signal — the loss FEC did not mask. Zero when FEC is
	// disabled or no data has flowed.
	ResidualLoss float64
}

// fecShardPayload builds the FEC data-shard coded bytes for outer-seq seq over the
// opaque inner datagram: seq (8 BE) || inner. The sender codes parity over this; the
// receiver reconstitutes the identical bytes from the DATA frame header + payload so
// the decoder's shards match what the encoder coded.
func fecShardPayload(seq uint64, inner []byte) []byte {
	b := make([]byte, fecSeqPrefixLen+len(inner))
	binary.BigEndian.PutUint64(b, seq)
	copy(b[fecSeqPrefixLen:], inner)
	return b
}

// splitFECShardPayload inverts fecShardPayload, returning the outer-seq and a fresh
// copy of the inner datagram. It fails fast on a shard too short to hold the prefix,
// which would indicate a decoder/encoder mismatch rather than a recoverable
// condition. The inner copy lets the resequencer take ownership without retaining the
// larger coded-shard backing array.
func splitFECShardPayload(b []byte) (uint64, []byte, error) {
	if len(b) < fecSeqPrefixLen {
		return 0, nil, fmt.Errorf("bind: recovered FEC shard %d bytes, shorter than the %d-byte outer-seq prefix", len(b), fecSeqPrefixLen)
	}
	seq := binary.BigEndian.Uint64(b[:fecSeqPrefixLen])
	inner := make([]byte, len(b)-fecSeqPrefixLen)
	copy(inner, b[fecSeqPrefixLen:])
	return seq, inner, nil
}

package bind

import (
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/frame"
)

// MTU accounting for the bonded datapath.
//
// A tunnelled application packet is wrapped in four nested layers before it hits
// the wire, each adding fixed overhead:
//
//		[ IP | UDP | outer DATA frame | WG transport | inner IP payload ]
//		  \___ IPv4UDPOverhead ___/   \_DataOverhead_/\_WGTransportOverhead_/
//
//	  - IP + UDP: the underlay carrying our outer datagram.
//	  - outer DATA frame: the bonding codec's nonce + DATA header (frame.DataOverhead).
//	  - WG transport: WireGuard's own data-message header + Poly1305 tag.
//
// InnerMTU sizes the TUN so a full-MTU inner packet, once wrapped in all four
// layers, still fits the path MTU without IP fragmentation. Fragmentation must be
// avoided: a fragment lost on a lossy WAN drops the whole datagram, and PMTUD
// black holes (ICMP "fragmentation needed" filtered by a middlebox) silently stall
// the tunnel. See docs/p1-mtu.md for the derivation and the MSS-clamping guidance
// that keeps TCP inside this budget.
const (
	// DefaultPathMTU is the assumed underlay path MTU when none is measured. 1500
	// is the near-universal Ethernet/most-broadband figure; deployments on links
	// with a smaller MTU (some LTE/PPPoE uplinks) must lower it.
	DefaultPathMTU = 1500

	// IPv4UDPOverhead is the outer IPv4 (20) + UDP (8) header cost. IPv4 is the
	// conservative default here; an IPv6 underlay costs 20 bytes more (see
	// IPv6UDPOverhead) so sizing for IPv4 and running over IPv6 only wastes a few
	// bytes, never fragments.
	IPv4UDPOverhead = 20 + 8

	// IPv6UDPOverhead is the outer IPv6 (40) + UDP (8) header cost.
	IPv6UDPOverhead = 40 + 8

	// WGTransportOverhead is WireGuard's per-datagram data-message overhead: the
	// 16-byte transport header (msg type + reserved + receiver index + counter)
	// plus the 16-byte Poly1305 authentication tag. Amnezia junk PREFIXES add
	// further variable bytes on top; they are handled as best-effort headroom, not
	// subtracted here, because they are configurable and per-packet variable.
	WGTransportOverhead = 16 + 16
)

// FECParityMTUPenalty is the extra bytes a full-size FEC PARITY frame occupies on the
// wire over a DATA frame carrying the same-size inner payload (T24). A parity frame is
// nonce + PARITY header + shard payload, where the shard payload is the codec's length
// prefix + the FEC outer-seq prefix + the largest coded inner payload; a data frame is
// nonce + DATA header + that same inner payload. So the delta is:
//
//	(ParityOverhead + ShardFramingOverhead + fecSeqPrefixLen) - DataOverhead  ==  5 bytes.
//
// When FEC is enabled the inner MTU is reduced by this penalty so a full-MTU DATA frame
// AND its group's PARITY frame both fit the path MTU — otherwise parity exceeds the
// path MTU by exactly this much and IP-fragments or is EMSGSIZE/PMTUD-blackholed, which
// silently kills the very redundancy FEC exists to provide on bulk full-size traffic.
const FECParityMTUPenalty = frame.ParityOverhead + fec.ShardFramingOverhead + fecSeqPrefixLen - frame.DataOverhead

// InnerMTU returns the largest inner (TUN) MTU that avoids IP fragmentation over
// an IPv4 underlay of the given path MTU: pathMTU minus the IP+UDP, outer DATA
// frame, and WireGuard transport overheads. fecEnabled additionally reserves the
// parity-over-data delta so a full-size parity frame also fits (see
// FECParityMTUPenalty); pass false when FEC is off to keep the pre-T24 budget.
func InnerMTU(pathMTU int, fecEnabled bool) int {
	return pathMTU - IPv4UDPOverhead - frame.DataOverhead - WGTransportOverhead - fecPenalty(fecEnabled)
}

// InnerMTU6 is InnerMTU for an IPv6 underlay.
func InnerMTU6(pathMTU int, fecEnabled bool) int {
	return pathMTU - IPv6UDPOverhead - frame.DataOverhead - WGTransportOverhead - fecPenalty(fecEnabled)
}

// fecPenalty is the inner-MTU reduction to reserve for FEC parity, or 0 when FEC is
// off.
func fecPenalty(fecEnabled bool) int {
	if fecEnabled {
		return FECParityMTUPenalty
	}
	return 0
}

