22		if k <= 0 || p <= 0 {
23			return 0
24		}
25		if p >= 1 {
26			// Every data shard lost (D = k with probability 1); m parity recover m of them.
27			if k > m {
28				return float64(k-m) / float64(k)
29			}
30			return 0
31		}
32		q := 1 - p
33		ratio := p / q
34		pmf := math.Pow(q, float64(k)) // P(D = 0)
35		var expected float64           // E[max(0, D-m)]
36		for d := 1; d <= k; d++ {
37			pmf *= float64(k-d+1) / float64(d) * ratio // advance to P(D = d)
38			if d > m {
39				expected += float64(d-m) * pmf
40			}
41		}
42		return expected / float64(k)
43	}
44	
45	// residualTargetParity derives the parity count M for the residual-SLA sizing mode:
46	// the SMALLEST m in [0, MaxParity] whose modeled binomial residual at the current
47	// smoothed loss is at/below the configured TargetResidual. It is used in place of
48	// the SafetyFactor redundancy map when TargetResidual is set.
49	//
50	// It is monotone non-decreasing in loss (a higher loss needs at least as much
51	// parity to hold the same residual), returns 0 at zero loss (zero overhead when
52	// clean), and saturates at MaxParity when even the parity ceiling cannot meet the
53	// target — the same shape the control law requires of the SafetyFactor map, so the
54	// hysteresis/slew machinery is unaffected by which mode is active.
55	func (c *Controller) residualTargetParity(loss float64) int {
56		if loss <= 0 {
57			return 0
58		}
59		for m := 0; m <= c.cfg.MaxParity; m++ {
60			if binomialResidual(c.cfg.DataShards, loss, m) <= c.cfg.TargetResidual {
